from jinja2 import DictLoader, FileSystemLoader, FunctionLoader, PrefixLoader, ChoiceLoader
from jinja2.exceptions import TemplateNotFound

def alias(t):
    return {'home': 'index.html'}.get(t, t)

loader = DictLoader({'index.html': 'hello'}, path_transform=alias)
print(loader.get_source(None, 'home'))

try:
    loader.get_source(None, 'missing')
except TemplateNotFound as e:
    print('not found:', e.name)

pl = PrefixLoader({'app1': DictLoader({'x.html': 'app1x'})})
print(pl.get_source(None, 'app1/x.html'))

def transform(t):
    return t.lstrip('/')

pl2 = PrefixLoader({'app1': DictLoader({'x.html': 'app1x'})}, path_transform=transform)
print(pl2.get_source(None, '/app1/x.html'))
"
